import { OidcProvider } from 'react-oidc';
import { AuthenticationProvider } from 'react-oidc-context';
import { UserManagerSettings, WebStorageStateStore, Log } from 'oidc-client';

Log.logger = console;
Log.level = Log.DEBUG;

const userManagerConfig = {
  authority: 'https://your-auth-server.com',
  client_id: 'your_client_id',
  redirect_uri: 'http://localhost:3000/callback',
  response_type: 'code',
  scope: 'openid profile email',
  post_logout_redirect_uri: 'http://localhost:3000',
  userStore: new WebStorageStateStore({ store: window.localStorage }),
};

const App = () => {
  const userManagerSettings = new UserManagerSettings(userManagerConfig);

  return (
    <Router>
      <OidcProvider userManagerSettings={userManagerSettings}>
        <AuthenticationProvider>
          <Switch>
            <Route path="/callback" component={CallbackPage} />
            <Route path="/" component={HomePage} />
          </Switch>
        </AuthenticationProvider>
      </OidcProvider>
    </Router>
  );
};

export default App;

// CallbackPage.js
import React, { useEffect } from 'react';
import { useOidc } from 'react-oidc';

const CallbackPage = () => {
  const { oidcUser, userManager } = useOidc();

  useEffect(() => {
    if (oidcUser && oidcUser.state) {
      userManager.signinRedirectCallback(oidcUser.state);
    }
  }, [oidcUser, userManager]);

  return <div>Logging in...</div>;
};

export default CallbackPage;

