import React from 'react';
import { useOidc } from 'react-oidc';

const HomePage = () => {
  const { oidcUser } = useOidc();

  return (
    <div>
      {oidcUser ? (
        <div>
          <h1>Welcome, {oidcUser.profile.name}</h1>
          <p>Email: {oidcUser.profile.email}</p>
        </div>
      ) : (
        <button onClick={() => oidcUser.signinRedirect()}>Login</button>
      )}
    </div>
  );
};

export default HomePage;